	printf("frame progress: ");
	fflush(NULL);

	for (int frame_no = 0; frame_no < common.frames_processed; frame_no++) {
#ifdef TIMING
		gettimeofday(&tv_h2d_start, NULL);
#endif
		fp* frame = get_frame(frames, frame_no, 0, 0, 1);
#ifdef TIMING
		gettimeofday(&tv_h2d_end, NULL);
		tvsub_local(&tv_h2d_end, &tv_h2d_start, &tv);
		h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
