#endif

#ifdef TEST_CHECKSUM
		for (i = 0; i < CHECK; i++) {
			checksum[i] = 0;
		}
#endif

#pragma omp parallel for schedule(static)
		for (int bx = 0; bx < common.allPoints; bx++) {
			kernel_gpu_openmp_point(
				common,
				frame,
				frame_no,
				d_endoRow,
				d_endoCol,
				tEndoRowLoc,
				tEndoColLoc,
				d_epiRow,
				d_epiCol,
				tEpiRowLoc,
				tEpiColLoc,
				d_endoT,
				d_epiT,
				d_in2_all,
				d_conv_all,
				d_in2_pad_cumv_all,
				d_in2_pad_cumv_sel_all,
				d_in2_sub_cumh_all,
				d_in2_sub_cumh_sel_all,
				d_in2_sub2_all,
				d_in2_sqr_all,
				d_in2_sqr_sub2_all,
				d_in_sqr_all,
				d_tMask_all,
				d_mask_conv_all,
				d_in_mod_temp_all,
				in_partial_sum_all,
				in_sqr_partial_sum_all,
				par_max_val_all,
				par_max_coo_all,
				in_final_sum_all,
				in_sqr_final_sum_all,
				denomT_all,
				checksum,
				bx);
		}

#ifdef TIMING
		gettimeofday(&tv_kernel_end, NULL);
		tvsub_local(&tv_kernel_end, &tv_kernel_start, &tv);
		kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

		free(frame);

		printf("%d ", frame_no);
		fflush(NULL);

#ifdef TEST_CHECKSUM
		printf("CHECKSUM:\n");
		for (i = 0; i < CHECK; i++) {
			printf("%f ", checksum[i]);
		}
		printf("\n\n");
#endif
	}

	printf("\n");
	fflush(NULL);

#ifdef TIMING
	gettimeofday(&tv_d2h_start, NULL);
#endif
#ifdef TIMING
	gettimeofday(&tv_d2h_end, NULL);
	tvsub_local(&tv_d2h_end, &tv_d2h_start, &tv);
	d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TEST_OUTPUT
	{
		int j;
		for (i = 0; i < common.frames_processed; i++) {
			printf("%d: ", i);
			for (j = 0; j < common.endoPoints; j++) {
				printf("%d ", tEndoRowLoc[j * common.no_frames + i]);
			}
			printf("\n\n");
		}
	}
#endif

#ifdef TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	free(d_endoRow);
	free(d_endoCol);
	free(d_epiRow);
	free(d_epiCol);

	free(d_endoT);
	free(d_epiT);
	free(d_in2_all);
	free(d_conv_all);
	free(d_in2_pad_cumv_all);
	free(d_in2_pad_cumv_sel_all);
	free(d_in2_sub_cumh_all);
	free(d_in2_sub_cumh_sel_all);
	free(d_in2_sub2_all);
	free(d_in2_sqr_all);
	free(d_in2_sqr_sub2_all);
	free(d_in_sqr_all);
	free(d_tMask_all);
	free(d_mask_conv_all);

	free(d_in_mod_temp_all);
	free(in_partial_sum_all);
	free(in_sqr_partial_sum_all);
	free(par_max_val_all);
	free(par_max_coo_all);
	free(in_final_sum_all);
	free(in_sqr_final_sum_all);
	free(denomT_all);

#ifdef TEST_CHECKSUM
	free(checksum);
#endif

#ifdef TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub_local(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
	tvsub_local(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

	printf("Time spent in different stages of the application:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}

int main(int argc, char* argv[]) {
	printf("WG size of kernel = %d \n", NUMBER_THREADS);

	params_common common;
	common.common_mem = sizeof(params_common);

	char* video_file_name = NULL;
	char* input_file_name = NULL;
	common.frames_processed = -1;

	for (int i = 0; i < argc; ++i) {
		switch (argv[i][1]) {
		case 'f':
			if (++i < argc) {
				video_file_name = argv[i];
			} else {
				printf("Could not read argument after option %s\n", argv[i - 1]);
				return 1;
			}
			break;
		case 'i':
			if (++i < argc) {
				input_file_name = argv[i];
			} else {
				printf("Could not read argument after option %s\n", argv[i - 1]);
				return 1;
			}
			break;
		case 'h':
			printf("%s <-f video_file> <-i input_file> <-n num_frames> [-p platform_id] [-n device_id]\n", argv[0]);
			return 0;
		case 'n':
			if (++i < argc) {
				common.frames_processed = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i - 1]);
				return 1;
			}
			break;
		case 'p':
			if (++i < argc) {
				platform_id_inuse = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i - 1]);
				return 1;
			}
			break;
		case 'd':
			if (++i < argc) {
				device_id_inuse = atoi(argv[i]);
			} else {
				printf("Could not read argument after option %s\n", argv[i - 1]);
				return 1;
			}
			break;
		}
	}

	if (input_file_name == NULL || video_file_name == NULL) {
		printf("Input or video file name is missing\n");
		return 0;
	}

	int i;
	avi_t* frames;

	frames = AVI_open_input_file(video_file_name, 1);
	if (frames == NULL) {
		AVI_print_error((char *)"Error with AVI_open_input_file");
		return -1;
	}

	common.no_frames = AVI_video_frames(frames);
	common.frame_rows = AVI_video_height(frames);
	common.frame_cols = AVI_video_width(frames);
	common.frame_elem = common.frame_rows * common.frame_cols;
	common.frame_mem = sizeof(fp) * common.frame_elem;

	if (common.frames_processed < 0 || common.frames_processed > common.no_frames) {
		printf("ERROR: %d is an incorrect number of frames specified, select in the range of 0-%d\n",
			common.frames_processed, common.no_frames);
		return 0;
	}

	read_parameters(input_file_name, &common.tSize, &common.sSize, &common.maxMove, &common.alpha);
	read_header(input_file_name, &common.endoPoints, &common.epiPoints);

	common.allPoints = common.endoPoints + common.epiPoints;

	common.endo_mem = sizeof(int) * common.endoPoints;
	int* endoRow = (int*)malloc(common.endo_mem);
	int* endoCol = (int*)malloc(common.endo_mem);
	int* tEndoRowLoc = (int*)malloc((size_t)common.endo_mem * common.no_frames);
	int* tEndoColLoc = (int*)malloc((size_t)common.endo_mem * common.no_frames);

	common.epi_mem = sizeof(int) * common.epiPoints;
	int* epiRow = (int*)malloc(common.epi_mem);
	int* epiCol = (int*)malloc(common.epi_mem);
	int* tEpiRowLoc = (int*)malloc((size_t)common.epi_mem * common.no_frames);
	int* tEpiColLoc = (int*)malloc((size_t)common.epi_mem * common.no_frames);

	read_data(input_file_name,
			  common.endoPoints, endoRow, endoCol,
			  common.epiPoints, epiRow, epiCol);

	kernel_gpu_opencl_wrapper(common,
							  endoRow,
							  endoCol,
							  tEndoRowLoc,
							  tEndoColLoc,
							  epiRow,
							  epiCol,
							  tEpiRowLoc,
							  tEpiColLoc,
							  frames);

#ifdef OUTPUT
	write_data("result.txt",
			   common.no_frames,
			   common.frames_processed,
			   common.endoPoints,
			   tEndoRowLoc,
			   tEndoColLoc,
			   common.epiPoints,
			   tEpiRowLoc,
			   tEpiColLoc);
#endif

	free(endoRow);
	free(endoCol);
	free(tEndoRowLoc);
	free(tEndoColLoc);

	free(epiRow);
	free(epiCol);
	free(tEpiRowLoc);
	free(tEpiColLoc);

	return 0;
}
